API_GATEWAY_VULNERABLE.example:
resource "aws_apigatewayv2_route" "example" {
  api_id    = aws_apigatewayv2_api.api.id
  route_key = "GET /private-data"

  authorization_type = "JWT"
  authorizer_id      = aws_apigatewayv2_authorizer.jwt.id
}

IAM_PERMISSIVE_POLICY.example:
resource "aws_iam_policy" "restricted_policy" {
  name        = "restricted_s3_policy"
  description = "Restricted S3 permissions"

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "s3:GetObject",
          "s3:PutObject"
        ]
        Resource = "arn:aws:s3:::my-private-bucket/*"
      }
    ]
  })
}
